import { chromium } from 'playwright';

const COOKIES_PATH = 'C:\\Users\\yyzypublic\\.openclaw\\workspace\\devops_cookies.json';
const PIPELINE_URL = 'https://devops.tencent.com/p/team-1e6d48f4846c421d6c827a5a9b0a71f2/pipeline/p-f78c977835c84b71a6d58b4746cd1c4a/build';

async function sleep(ms) {
  return new Promise(r => setTimeout(r, ms));
}

async function waitForSelector(page, selector, timeout = 15000) {
  try {
    await page.waitForSelector(selector, { timeout });
    return true;
  } catch {
    return false;
  }
}

async function main() {
  console.log('[DEVOP] 正在启动浏览器...');
  const browser = await chromium.launch({ headless: true });
  const context = await browser.newContext({
    viewport: { width: 1920, height: 1080 },
    userAgent: 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
    locale: 'zh-CN',
  });

  // Load cookies
  const fs = await import('fs');
  const cookies = JSON.parse(fs.readFileSync(COOKIES_PATH, 'utf-8'));
  await context.addCookies(cookies.map(c => ({
    name: c.name,
    value: c.value,
    domain: c.domain,
    path: c.path,
    httpOnly: c.httpOnly || false,
    secure: c.secure || false,
    sameSite: c.sameSite || 'Lax',
  })));

  const page = await context.newPage();

  // Navigate to pipeline page
  console.log('[DEVOP] 正在打开流水线页面...');
  await page.goto(PIPELINE_URL, { waitUntil: 'networkidle', timeout: 30000 });
  console.log('[DEVOP] 页面加载完成，当前URL:', page.url());

  // Check if redirected to login
  if (page.url().includes('login') || page.url().includes('auth')) {
    console.error('[DEVOP] 被重定向到登录页，Cookie 可能已失效');
    await browser.close();
    process.exit(1);
  }

  await sleep(2000);

  // Click "启动新构建" button
  console.log('[DEVOP] 正在查找「启动新构建」按钮...');
  let startBtn = await page.$('button:has-text("启动新构建")');
  if (!startBtn) {
    startBtn = await page.$('span:has-text("启动新构建")');
  }
  if (!startBtn) {
    startBtn = await page.$('text=启动新构建');
  }
  if (!startBtn) {
    // Try XPath
    startBtn = await page.$('//*[contains(text(), "启动新构建")]');
  }

  if (startBtn) {
    console.log('[DEVOP] 点击「启动新构建」');
    await startBtn.click();
  } else {
    console.log('[DEVOP] 未找到「启动新构建」按钮，尝试截图定位...');
    // Check if build dialog is already open
    console.log('[DEVOP] 页面标题:', await page.title());
    await page.screenshot({ path: 'devops_debug_1.png', fullPage: true });
    console.log('[DEVOP] 已保存截图 devops_debug_1.png');
    // Let's try clicking by class or aria-label
    const buttons = await page.$$('button');
    for (const btn of buttons) {
      const text = await btn.textContent();
      if (text && text.includes('启动')) {
        console.log('[DEVOP] 找到按钮文字:', text);
        await btn.click();
        break;
      }
    }
  }

  await sleep(3000);

  // Look for dest field/parameter
  console.log('[DEVOP] 正在查找 dest 参数输入框...');
  let destInput = await page.$('input[placeholder*="dest"]');
  if (!destInput) {
    destInput = await page.$('input[value*="1v1"]');
  }
  if (!destInput) {
    destInput = await page.$('//label[contains(text(), "dest")]/following::input[1]');
  }
  if (!destInput) {
    // Try to find all visible inputs
    const inputs = await page.$$('input:visible');
    for (const inp of inputs) {
      const placeholder = await inp.getAttribute('placeholder');
      const name = await inp.getAttribute('name');
      const id = await inp.getAttribute('id');
      const val = await inp.inputValue();
      console.log(`[DEVOP] Input: placeholder="${placeholder}", name="${name}", id="${id}", value="${val}"`);
    }
  }

  if (destInput) {
    console.log('[DEVOP] 找到 dest 输入框，当前值:', await destInput.inputValue());
    await destInput.click({ clickCount: 3 }); // Select all
    await destInput.fill('1v1_qa');
    console.log('[DEVOP] 已将 dest 设为 1v1_qa');
  } else {
    console.log('[DEVOP] 未找到 dest 输入框，尝试查找下拉选择...');
    // Maybe it's a select/dropdown
    const selects = await page.$$('select');
    for (const sel of selects) {
      const name = await sel.getAttribute('name');
      const id = await sel.getAttribute('id');
      console.log(`[DEVOP] Select: name="${name}", id="${id}"`);
    }
    // Try to find by label text
    const labels = await page.$$('label:visible');
    for (const label of labels) {
      const text = await label.textContent();
      if (text && text.toLowerCase().includes('dest')) {
        console.log('[DEVOP] 找到 dest 标签:', text);
        const forAttr = await label.getAttribute('for');
        if (forAttr) {
          destInput = await page.$(`#${forAttr}`);
          if (destInput) {
            await destInput.click({ clickCount: 3 });
            await destInput.fill('1v1_qa');
            console.log('[DEVOP] 已将 dest 设为 1v1_qa');
          }
        }
      }
    }
  }

  if (!destInput) {
    console.log('[DEVOP] 仍未找到 dest，保存截图排查...');
    await page.screenshot({ path: 'devops_debug_2.png', fullPage: true });
    console.log('[DEVOP] 已保存截图 devops_debug_2.png');
  }

  await sleep(1000);

  // Click submit/confirm button
  console.log('[DEVOP] 正在查找提交/确认按钮...');
  let submitBtn = await page.$('button:has-text("确定")');
  if (!submitBtn) {
    submitBtn = await page.$('button:has-text("提交")');
  }
  if (!submitBtn) {
    submitBtn = await page.$('button:has-text("确认")');
  }
  if (!submitBtn) {
    submitBtn = await page.$('button:has-text("运行")');
  }
  if (!submitBtn) {
    submitBtn = await page.$('span:has-text("确定")');
  }
  if (!submitBtn) {
    submitBtn = await page.$('//*[contains(text(), "确定")]');
  }

  if (submitBtn) {
    console.log('[DEVOP] 点击提交按钮:', await submitBtn.textContent());
    await submitBtn.click();
  } else {
    console.log('[DEVOP] 未找到提交按钮，保存截图...');
    await page.screenshot({ path: 'devops_debug_3.png', fullPage: true });
  }

  // Wait for build to start
  console.log('[DEVOP] 等待构建启动...');
  await sleep(5000);

  // Check if build is running
  console.log('[DEVOP] 当前URL:', page.url());

  // Wait for build to complete - poll for status
  let buildComplete = false;
  let attempts = 0;
  const maxAttempts = 60; // 10 minutes max

  while (!buildComplete && attempts < maxAttempts) {
    await sleep(10000); // Check every 10 seconds
    attempts++;
    console.log(`[DEVOP] 检查构建状态 (${attempts}/${maxAttempts})...`);

    // Check page for completion indicators
    const content = await page.content();

    if (content.includes('构建成功') || content.includes('成功') && content.includes('构建完成')) {
      console.log('[DEVOP] 构建成功！');
      buildComplete = true;
      break;
    }
    if (content.includes('构建失败') || content.includes('失败')) {
      console.log('[DEVOP] 构建失败！');
      buildComplete = true;
      break;
    }

    // Reload page to refresh status
    await page.reload({ waitUntil: 'networkidle', timeout: 30000 });
    await sleep(2000ush);
  }

  if (!buildComplete) {
    console.log('[DEVOP] 超时，构建状态未知');
  }

  // Save final screenshot
  await page.screenshot({ path: 'devops_result.png', fullPage: true });
  console.log('[DEVOP] 已保存截图 devops_result.png');

  await browser.close();
  console.log('[DEVOP] 完成');
}

main().catch(err => {
  console.error('[DEVOP] 错误:', err.message);
  process.exit(1);
});

