// DevOps Cookie Keepalive Script
// Loads cookies, visits the DevOps pipelines page to refresh server-side session,
// then saves the new cookies back to devops_cookies.json.
// Run periodically (every 1-2 days) to keep login alive.
//
// Exit codes:
//   0 = success (cookies refreshed)
//   1 = cookie invalid / login expired (need re-login)
//   2 = script error (network, etc.)

import { chromium } from 'playwright';
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const WORKSPACE_DIR = path.resolve(__dirname, '..');
const COOKIES_FILE = path.join(WORKSPACE_DIR, 'devops_cookies.json');
const STATE_FILE = path.join(WORKSPACE_DIR, 'memory', 'devops-keepalive-state.json');

function log(msg) {
  console.log(`[${new Date().toISOString()}] ${msg}`);
}

function writeState(state) {
  try {
    fs.mkdirSync(path.dirname(STATE_FILE), { recursive: true });
    fs.writeFileSync(STATE_FILE, JSON.stringify(state, null, 2));
  } catch (e) {
    console.error('Failed to write state:', e.message);
  }
}

async function main() {
  if (!fs.existsSync(COOKIES_FILE)) {
    log(`ERROR: cookies file not found: ${COOKIES_FILE}`);
    writeState({ ok: false, error: 'cookies_missing', at: new Date().toISOString() });
    process.exit(1);
  }

  const oldCookies = JSON.parse(fs.readFileSync(COOKIES_FILE, 'utf8'));
  log(`Loaded ${oldCookies.length} cookies`);

  const browser = await chromium.launch({
    headless: true,
    args: ['--no-sandbox', '--disable-blink-features=AutomationControlled'],
  });
  const ctx = await browser.newContext({
    locale: 'zh-CN',
    viewport: { width: 1920, height: 1080 },
    ignoreHTTPSErrors: true,
  });
  await ctx.addCookies(oldCookies);
  const page = await ctx.newPage();

  try {
    log('Visiting DevOps pipelines page...');
    const resp = await page.goto('https://devops.devcloud.ztgame.com/projects/yyzy/pipelines', {
      waitUntil: 'domcontentloaded',
      timeout: 30000,
    });
    await page.waitForTimeout(3000);

    const url = page.url();
    const title = await page.title();
    const status = resp?.status();
    const bodyText = await page.evaluate(() => document.body.innerText.substring(0, 500));
    log(`HTTP ${status} | url=${url} | title=${title}`);
    log(`Body preview: ${bodyText.substring(0, 200)}`);

    // Check if we got redirected to login
    if (url.includes('login') || title.includes('登录') || title.includes('LOGIN') || bodyText.includes('登录')) {
      log('❌ Session EXPIRED - need re-login');
      writeState({
        ok: false,
        error: 'session_expired',
        at: new Date().toISOString(),
        finalUrl: url,
        title,
      });
      await browser.close();
      process.exit(1);
    }

    // Also visit the pipeline detail page to deepen the session
    await page.goto('https://devops.devcloud.ztgame.com/projects/yyzy/pipelines/p-f78c977835c84b71a6d58b4746cd1c4a', {
      waitUntil: 'domcontentloaded',
      timeout: 30000,
    }).catch(() => {});
    await page.waitForTimeout(2000);

    // Save refreshed cookies
    const newCookies = await ctx.cookies();
    fs.writeFileSync(COOKIES_FILE, JSON.stringify(newCookies, null, 2));

    log(`✅ Refreshed ${newCookies.length} cookies`);
    writeState({
      ok: true,
      at: new Date().toISOString(),
      cookieCount: newCookies.length,
      title,
    });

    await browser.close();
    process.exit(0);
  } catch (e) {
    log(`ERROR: ${e.message}`);
    writeState({ ok: false, error: e.message, at: new Date().toISOString() });
    try { await browser.close(); } catch {}
    process.exit(2);
  }
}

main();

