import { chromium } from 'playwright';
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const WORKSPACE_DIR = path.resolve(__dirname, '..');
const COOKIES_FILE = path.join(WORKSPACE_DIR, 'devops_cookies.json');

// Correct DevOps URL from internal network
const PIPELINE_URL = 'https://devops.devcloud.ztgame.com/projects/yyzy/pipelines/p-f78c977835c84b71a6d58b4746cd1c4a';

function log(msg) {
  console.log(`[DEVOP] ${msg}`);
}

async function sleep(ms) {
  return new Promise(r => setTimeout(r, ms));
}

async function main() {
  // Check cookies
  if (!fs.existsSync(COOKIES_FILE)) {
    log('ERROR: cookies file not found');
    process.exit(1);
  }
  const cookies = JSON.parse(fs.readFileSync(COOKIES_FILE, 'utf8'));
  log(`Loaded ${cookies.length} cookies`);

  log('正在启动浏览器...');
  const browser = await chromium.launch({ headless: true });
  const context = await browser.newContext({
    viewport: { width: 1920, height: 1080 },
    locale: 'zh-CN',
    userAgent: 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
  });

  // Load cookies
  await context.addCookies(cookies.map(c => ({
    name: c.name,
    value: c.value,
    domain: c.domain,
    path: c.path,
    httpOnly: c.httpOnly || false,
    secure: c.secure || false,
    sameSite: c.sameSite || 'Lax',
  })));

  const page = await context.newPage();

  // Navigate to pipeline page
  log('正在打开流水线页面...');
  await page.goto(PIPELINE_URL, { waitUntil: 'networkidle', timeout: 30000 });
  const url = page.url();
  const title = await page.title();
  log(`页面加载完成: ${title} | ${url}`);

  // Check for login redirect
  if (url.includes('login') || (await page.content()).includes('登录')) {
    log('❌ 被重定向到登录页，Cookie 已失效');
    await browser.close();
    process.exit(1);
  }

  await sleep(2000);

  // Take a debug screenshot
  await page.screenshot({ path: path.join(WORKSPACE_DIR, 'devops_step1.png'), fullPage: true });
  log('已保存截图 devops_step1.png');

  // Click "启动新构建" or "新建构建" or similar button
  log('正在查找「启动新构建」按钮...');

  // Try multiple selector strategies
  const btnSelectors = [
    'button:has-text("启动新构建")',
    'button:has-text("新建构建")',
    'button:has-text("构建")',
    'text=启动新构建',
    'text=新建构建',
    '//button[contains(text(), "启动")]',
    '//button[contains(text(), "新建")]',
    '//span[contains(text(), "启动新构建")]',
  ];

  let clicked = false;
  for (const sel of btnSelectors) {
    try {
      const btn = await page.$(sel);
      if (btn) {
        const text = await btn.textContent();
        log(`找到按钮: "${text?.trim()}" (selector: ${sel})`);
        await btn.click();
        clicked = true;
        break;
      }
    } catch {}
  }

  if (!clicked) {
    // Look for any button with build-related text
    const allBtns = await page.$$('button, a, span');
    for (const el of allBtns) {
      try {
        const text = await el.textContent();
        if (text && (text.includes('启动') || text.includes('新建') || text.includes('触发'))) {
          log(`找到元素: "${text.trim()}"`);
          await el.click();
          clicked = true;
          break;
        }
      } catch {}
    }
  }

  if (!clicked) {
    log('❌ 未找到「启动新构建」按钮');
    await page.screenshot({ path: path.join(WORKSPACE_DIR, 'devops_error.png'), fullPage: true });
    await browser.close();
    process.exit(1);
  }

  await sleep(3000);
  await page.screenshot({ path: path.join(WORKSPACE_DIR, 'devops_step2.png'), fullPage: true });
  log('已保存截图 devops_step2.png');

  // Now find the dest parameter
  log('正在查找 dest 参数...');

  // Look for dest field - could be input, select, or dropdown
  let destFound = false;

  // Strategy 1: Find input with placeholder or label containing "dest"
  const destSelectors = [
    'input[placeholder*="dest" i]',
    'input[name*="dest" i]',
    'input[id*="dest" i]',
    'select[name*="dest" i]',
    'select[id*="dest" i]',
    '//input[contains(translate(@placeholder, "DEST", "dest"), "dest")]',
    '//label[contains(text(), "dest") or contains(text(), "Dest")]/following::input[1]',
    '//label[contains(text(), "dest") or contains(text(), "Dest")]/following::select[1]',
    '//span[contains(text(), "dest") or contains(text(), "Dest")]/following::input[1]',
    '//span[contains(text(), "dest") or contains(text(), "Dest")]/following::select[1]',
  ];

  for (const sel of destSelectors) {
    try {
      const el = await page.$(sel);
      if (el) {
        const tagName = await el.evaluate(e => e.tagName.toLowerCase());
        const val = await el.inputValue().catch(() => '');
        log(`找到 dest 元素: <${tagName}> value="${val}" (selector: ${sel})`);

        if (tagName === 'select') {
          await el.selectOption('1v1_qa');
          log('已将 dest 选择为 1v1_qa');
        } else {
          await el.click({ clickCount: 3 });
          await el.fill('1v1_qa');
          log('已将 dest 设为 1v1_qa');
        }
        destFound = true;
        break;
      }
    } catch {}
  }

  // Strategy 2: Search page for "dest" text and try to find nearby input
  if (!destFound) {
    log('尝试查找页面中所有输入框...');
    const inputs = await page.$$('input:visible, select:visible');
    for (const inp of inputs) {
      try {
        const tagName = await inp.evaluate(e => e.tagName.toLowerCase());
        const placeholder = await inp.getAttribute('placeholder');
        const name = await inp.getAttribute('name');
        const id = await inp.getAttribute('id');
        const val = await inp.inputValue().catch(() => '');

        if (placeholder?.toLowerCase().includes('dest') || name?.toLowerCase().includes('dest') || id?.toLowerCase().includes('dest')) {
          log(`找到 dest: <${tagName}> name="${name}" placeholder="${placeholder}" value="${val}"`);
          if (tagName === 'select') {
            await inp.selectOption('1v1_qa');
          } else {
            await inp.click({ clickCount: 3 });
            await inp.fill('1v1_qa');
          }
          destFound = true;
          break;
        }

        // If input has value like 1v1_test or similar, it's likely the dest
        if (val && val.startsWith('1v1_')) {
          log(`找到可能 dest 输入: <${tagName}> name="${name}" placeholder="${placeholder}" value="${val}"`);
          if (tagName === 'select') {
            await inp.selectOption('1v1_qa');
          } else {
            await inp.click({ clickCount: 3 });
            await inp.fill('1v1_qa');
          }
          destFound = true;
          break;
        }
      } catch {}
    }
  }

  if (!destFound) {
    log('⚠️ 未找到 dest 参数，尝试继续...');
    await page.screenshot({ path: path.join(WORKSPACE_DIR, 'devops_dest_not_found.png'), fullPage: true });
  }

  await sleep(1000);

  // Click the submit/confirm button
  log('正在查找提交按钮...');
  const submitSelectors = [
    'button:has-text("确定")',
    'button:has-text("提交")',
    'button:has-text("运行")',
    'button:has-text("确认")',
    'button:has-text("立即构建")',
    '//button[contains(text(), "确定")]',
    '//button[contains(text(), "提交")]',
    '//button[contains(text(), "运行")]',
    '//span[contains(text(), "确定")]',
  ];

  let submitted = false;
  for (const sel of submitSelectors) {
    try {
      const btn = await page.$(sel);
      if (btn) {
        const text = await btn.textContent();
        log(`找到提交按钮: "${text?.trim()}"`);
        await btn.click();
        submitted = true;
        break;
      }
    } catch {}
  }

  if (!submitted) {
    // Try to find any button that looks like confirm/submit in a dialog
    const allBtns = await page.$$('button');
    for (const btn of allBtns) {
      try {
        const text = await btn.textContent();
        if (text && (text.includes('确定') || text.includes('提交') || text.includes('运行') || text.includes('确认'))) {
          log(`找到提交按钮: "${text.trim()}"`);
          await btn.click();
          submitted = true;
          break;
        }
      } catch {}
    }
  }

  if (!submitted) {
    log('⚠️ 未找到提交按钮，尝试按 Enter');
    await page.keyboard.press('Enter');
    submitted = true;
  }

  await sleep(3000);
  await page.screenshot({ path: path.join(WORKSPACE_DIR, 'devops_step3.png'), fullPage: true });
  log('已保存截图 devops_step3.png');

  // Now monitor build status
  log('等待构建启动并监控状态...');
  await sleep(8000);

  // Navigate back to pipeline page to see build status
  // The URL might have changed to show build details

  // Poll for build status
  let buildCompleted = false;
  let buildResult = 'unknown';
  let buildNumber = '';

  for (let i = 0; i < 60; i++) {
    await sleep(10000);
    log(`检查构建状态 (${i + 1}/60)...`);

    try {
      await page.reload({ waitUntil: 'networkidle', timeout: 30000 });
      await sleep(2000);
    } catch {
      continue;
    }

    const content = await page.content();

    // Check for build number in current URL
    const currentUrl = page.url();
    const buildMatch = currentUrl.match(/build\/(\d+)/);
    if (buildMatch) {
      buildNumber = buildMatch[1];
    }

    // Check for success/failure indicators
    if (content.includes('构建成功') || content.includes('构建完成') || content.includes('成功')) {
      // Look for success icon/status
      const successIndicators = [
        'svg[class*="success"]',
        'svg[class*="check"]',
        '[class*="status-success"]',
        '[class*="passed"]',
        '//*[contains(@class, "success")]',
      ];
      for (const sel of successIndicators) {
        try {
          const el = await page.$(sel);
          if (el) {
            buildCompleted = true;
            buildResult = 'success';
            log('✅ 构建成功！');
            break;
          }
        } catch {}
      }
      if (buildCompleted) break;
    }

