import { chromium } from 'playwright';
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const WORKSPACE_DIR = path.resolve(__dirname, '..');
const COOKIES_FILE = path.join(WORKSPACE_DIR, 'devops_cookies.json');
const PIPELINE_URL = 'https://devops.devcloud.ztgame.com/projects/yyzy/pipelines/p-f78c977835c84b71a6d58b4746cd1c4a';

function log(msg) { console.log(`[DEVOP] ${msg}`); }
async function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

async function main() {
  if (!fs.existsSync(COOKIES_FILE)) { log('❌ Cookie 文件不存在'); process.exit(1); }
  const cookies = JSON.parse(fs.readFileSync(COOKIES_FILE, 'utf8'));
  log(`已加载 ${cookies.length} 个 Cookie`);

  const browser = await chromium.launch({ headless: true });
  const context = await browser.newContext({ viewport: { width: 1920, height: 1080 }, locale: 'zh-CN' });
  await context.addCookies(cookies.map(c => ({
    name: c.name, value: c.value, domain: c.domain, path: c.path,
    httpOnly: c.httpOnly || false, secure: c.secure || false, sameSite: c.sameSite || 'Lax',
  })));
  const page = await context.newPage();

  log('打开流水线页面...');
  await page.goto(PIPELINE_URL, { waitUntil: 'networkidle', timeout: 30000 });
  if ((await page.content()).includes('登录') || page.url().includes('login')) {
    log('❌ Cookie 已失效'); await browser.close(); process.exit(1);
  }
  log(`已加载: ${page.url()}`);

  // Click "启动新构建"
  log('点击「启动新构建」...');
  const startBtn = await page.$('button:has-text("启动新构建")');
  if (!startBtn) { log('❌ 未找到按钮'); await browser.close(); process.exit(1); }
  await startBtn.click();
  await sleep(3000);

  // Verify dest is already 1v1_qa
  const destSpan = await page.$('.ant-select-selection-item');
  if (destSpan) {
    const destVal = await destSpan.textContent();
    log(`dest = "${destVal}"`);
  }

  // Click the confirm button - "执 行" (the Ant Design button has space in Chinese chars)
  log('查找「执 行」按钮...');

  // Method 1: Find by text content, normalize spaces
  const allButtons = await page.$$('button');
  let execBtn = null;
  for (const btn of allButtons) {
    const text = ((await btn.textContent()) || '').replace(/\s+/g, ''); // Normalize: remove all whitespace
    if (text === '执行' || text === '确定' || text === '提交' || text === '运行' || text === '确认') {
      execBtn = btn;
      log(`找到按钮: "${await btn.textContent()}" (归一化: "${text}")`);
      break;
    }
  }

  if (!execBtn) {
    // Method 2: Find by class + type
    execBtn = await page.$('button.ant-btn-primary:not(.ant-modal-close)');
    if (execBtn) {
      const txt = await execBtn.textContent();
      log(`找到主按钮: "${txt}"`);
    }
  }

  if (!execBtn) {
    // Method 3: Find by position (the close button is at top-right, exec is in dialog footer)
    const dialog = await page.$('.ant-modal');
    if (dialog) {
      execBtn = await dialog.$('button.ant-btn-primary');
      if (execBtn) {
        const txt = await execBtn.textContent();
        log(`在 dialog 中找到主按钮: "${txt}"`);
      }
    }
  }

  if (execBtn) {
    await execBtn.click();
    log('✅ 已点击执行按钮！');
  } else {
    log('❌ 找不到执行按钮');
    await page.screenshot({ path: path.join(WORKSPACE_DIR, 'devops_no_btn.png'), fullPage: true });
    await browser.close();
    process.exit(1);
  }

  // Wait for build to trigger
  log('等待构建触发...');
  await sleep(5000);

  // Now the dialog should be gone. Reload to see build progress
  await page.goto(PIPELINE_URL, { waitUntil: 'networkidle', timeout: 30000 });
  await sleep(2000);
  log(`构建页面: ${page.url()}`);

  // Monitor build status
  let buildDone = false;
  let result = 'unknown';
  for (let i = 0; i < 40; i++) {
    await sleep(10000);
    log(`检查构建状态 (${i+1}/40)...`);

    const text = await page.evaluate(() => document.body.innerText);

    // Check for success
    if (text.includes('构建成功') || (text.includes('成功') && !text.includes('失败'))) {
      const ok = await page.$('[class*="success"], [class*="passed"], svg[class*="check"]');
      if (ok) { result = 'success'; buildDone = true; log('✅ 构建成功！'); break; }
    }
    if (text.includes('构建失败') || text.includes('失败')) {
      const bad = await page.$('[class*="fail"], [class*="error"], svg[class*="close"]');
      if (bad) { result = 'failed'; buildDone = true; log('❌ 构建失败'); break; }
    }

    log(`  状态: ${text.includes('运行中') ? '运行中' : '等待中'}`);
    await page.reload({ waitUntil: 'networkidle', timeout: 30000 }).catch(() => {});
    await sleep(2000);
  }

  await page.screenshot({ path: path.join(WORKSPACE_DIR, 'devops_final_result.png'), fullPage: true });

  const newCookies = await context.cookies();
  fs.writeFileSync(COOKIES_FILE, JSON.stringify(newCookies, null, 2));
  await browser.close();

  if (result === 'success') { log('✅ 1v1_qa 服构建成功！'); process.exit(0); }
  else if (result === 'failed') { log('❌ 1v1_qa 服构建失败！'); process.exit(1); }
  else { log('⚠️ 构建状态未知，请去 DevOps 页面确认'); process.exit(2); }
}

main().catch(err => { console.error(`[DEVOP] 错误: ${err.message}`); process.exit(1); });
